import React, { useState, useEffect } from 'react';
import { BarChart3, Database } from 'lucide-react';
import MetricsSelector from './components/MetricsSelector';
import MetricDataViewer from './components/MetricDataViewer';
import HomePage from './components/HomePage';
import MainLayout from './components/layout/MainLayout';
import './App.css';

const NAV_LABELS = {
  home: 'Home',
  dashboards: 'Dashboards',
  alerts: 'Alerts',
  'data-sources': 'Data Sources',
  reports: 'Reports',
  'user-management': 'User Management',
  'system-status': 'System Status',
  settings: 'Settings',
};

function SectionPlaceholder({ title }) {
  return (
    <div className="opsight-placeholder">
      <div className="opsight-placeholder__card">
        <h2>{title}</h2>
        <p>This section is coming soon.</p>
      </div>
    </div>
  );
}

function App() {
  const [activeNavId, setActiveNavId] = useState('home');
  const [selectedMetric, setSelectedMetric] = useState(null);
  const [metrics, setMetrics] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchMetrics();
  }, []);

  const fetchMetrics = async (options) => {
    const silent = options && options.silent;
    try {
      if (!silent) setLoading(true);
      
      // Get available metrics from Prometheus Query API
      const response = await fetch('/api/v1/label/__name__/values');
      const data = await response.json();
      
      if (data.status === 'success' && data.data) {
        const metricNames = data.data;
        const parsedMetrics = [];
        
        // Get metadata for each metric
        const metadataResponse = await fetch('/api/v1/metadata');
        const metadataData = await metadataResponse.json();
        
        metricNames.forEach(name => {
          const metadata = metadataData.data[name];
          if (metadata && metadata.length > 0) {
            parsedMetrics.push({
              name: name,
              description: metadata[0].help || 'No description available',
              type: metadata[0].type || 'unknown',
              help: metadata[0].help || 'No description available'
            });
          } else {
            parsedMetrics.push({
              name: name,
              description: 'No description available',
              type: 'unknown',
              help: 'No description available'
            });
          }
        });
        
        setMetrics(parsedMetrics);
        setError(null);
      } else {
        setError('Failed to parse metrics data');
      }
      
      if (!silent) setLoading(false);
    } catch (err) {
      setError('Failed to fetch metrics: ' + err.message);
      if (!silent) setLoading(false);
    }
  };

  const handleMetricSelect = (metric) => {
    setSelectedMetric(metric);
  };

  if (loading) {
    return (
      <div className="loading">
        <img src="/opsight-logo.svg" alt="OpSight Logo" className="loading-logo animate-spin" />
        <span className="ml-2">Loading OpSight metrics...</span>
      </div>
    );
  }

  if (error) {
    return (
      <div className="error">
        <h2>Error</h2>
        <p>{error}</p>
        <button className="btn btn-primary mt-4" onClick={fetchMetrics}>
          Retry
        </button>
      </div>
    );
  }

  const sectionLabel = NAV_LABELS[activeNavId] || 'Home';

  let mainContent;
  if (activeNavId === 'home') {
    mainContent = (
      <HomePage
        metrics={metrics}
        onOpenDashboards={() => setActiveNavId('dashboards')}
        onNavigate={setActiveNavId}
      />
    );
  } else if (activeNavId === 'dashboards') {
    mainContent = (
      <div className="dashboard">
        <div className="dashboard-header"></div>

        <div className="dashboard-grid">
          <div className="metrics-panel">
            <div className="panel-header">
              <BarChart3 size={20} />

              <span className="metric-count">{metrics.length} metrics</span>
            </div>
            <MetricsSelector
              metrics={metrics}
              onMetricSelect={handleMetricSelect}
              selectedMetric={selectedMetric}
            />
          </div>

          <div className="data-panel">
            {selectedMetric ? (
              <MetricDataViewer metric={selectedMetric} />
            ) : (
              <div className="no-selection">
                <Database size={48} />
                <h3>Select a Metric</h3>
                <p>Choose a metric from the left panel to view its real-time data</p>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  } else {
    mainContent = (
      <SectionPlaceholder title={sectionLabel} />
    );
  }

  return (
    <MainLayout
      activeNavId={activeNavId}
      onNavChange={setActiveNavId}
      sectionLabel={sectionLabel}
      onRefresh={() => fetchMetrics({ silent: true })}
    >
      {mainContent}
    </MainLayout>
  );
}

export default App;
